-- ============================================================
-- Seed Data: Mock Business Data (mock_business_data table)
-- ============================================================
-- Description: Simulated operational metrics for occupied units
-- Generated: 2026-04-19
--
-- Coverage:
--   - 53 units with ACTIVE contracts and OCCUPIED status
--   - 6 months: 2025-11-01 to 2026-04-01 (monthly on 1st)
--   - Total: 318 records
--
-- Data Generation Rules:
--   - daily_traffic: random 200-2000, scaled by gross_area
--   - daily_sales: daily_traffic * random(50-200) yuan/visitor
--   - monthly_sales: daily_sales * 30
--   - sales_per_sqm: monthly_sales / gross_area
--   - rent_to_sales_ratio: (monthly_rent / monthly_sales) * 100, clamped 8%-25%
--
-- Usage:
--   docker exec -i camp-postgres psql -U cdata -d cdata < scripts/seed_mock_biz_data.sql
-- ============================================================

